import React from 'react'
import { Modal, Avatar, message } from 'antd';
import CopyClipboardIcon from '../../../images/content_copy.svg'
import '../../../CSS/ViewAPIDocModalStyle.css';
import { LEFT_TABS, PARTY_MASTER_API, PARCEL_SHOP_MASTER_API } from '../../../utils/constants'
import { containerConstantsService } from '../../../utils/containerconstants/ContainerConstants';

const containerConstants = containerConstantsService.getInstance();

const ViewAPIDocModal = (props) => {

    const apiDocNumList = [];
    const apiDocList = [];
    let spaceCount = 0;

    let indexVal = 0;

    const selectText = () => {
        const text = document.getElementById('APIDocContent');
        let range;
        let selection;
        if (document.body.createTextRange) {
            range = document.body.createTextRange();
            range.moveToElementText(text);
            range.select();
        } else if (window.getSelection) {
            selection = window.getSelection();
            range = document.createRange();
            range.selectNodeContents(text);
            selection.removeAllRanges();
            selection.addRange(range);
        }
        return range;
    }

    const copyText = () => {
        const text = selectText('APIDocContent');
        navigator.clipboard.writeText(text);
        message.success('copied!');

    }

    const apiDoc = () =>{

        return props.activeTabPaneKey === LEFT_TABS.PARTY_MASTER_TABPANE ?
            //JSON.stringify(data2.partyMaster, undefined, 5).replace('{\n', '').replace('\n}', '').replaceAll('"', '')
            PARTY_MASTER_API
            :
            PARCEL_SHOP_MASTER_API;

    }

    const getData = (obj) => {
        Object.entries(obj).forEach(([key, value], index) => {
            apiDocNumList.push(<span>{indexVal + 1}</span>)
            indexVal++;
            if(typeof value === 'object' && value !== null ){

                let data = '';
                for(let i =0 ; i< spaceCount; i++){
                    data+='    ';
                }

                apiDocList.push(<p>{data}{key} : {'{'}</p>);
                spaceCount++;
                getData(value);
                spaceCount--;
                data = '';
                for(let i =0 ; i< spaceCount; i++){
                    data+='    ';
                }
                apiDocList.push(<p>{data}{'},'}</p>);
            }else{
                let data = '';
                for(let i =0 ; i< spaceCount; i++){
                    data+='    ';
                }
                apiDocList.push( <p>{data}{key} : {value},</p>);
            }
          })
          return apiDocNumList   ;
    }

    return (
        <div>
            <Modal
                title={<div className='api-doc-modal-header-title'> <div>{containerConstants.formatString(containerConstants.VIEW_API_DOC)}</div><Avatar onClick={copyText} shape='square' src={CopyClipboardIcon} /></div>}
                className='master-data-modal-api-doc'
                visible={props.showAPIDocModal}
                centered={true}
                footer={null}
                onCancel={() => props.setShowAPIDocModal(false)}
            >
                <div className='api-doc-container'>
                    <div className='api-doc-list-number'>
                        {getData(apiDoc())}
                    </div>
                    <pre id="APIDocContent">
                        {apiDocList}
                    </pre>
                </div>
            </Modal>
        </div>
    )
}

export default ViewAPIDocModal
